+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { isRelation, isRelationPair } from '../relation/utils/is-relation';
+import { getStore, hasTrait } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import { createModifier } from './modifier';
+import type { Predicate, PredicateValues, QueryInstance } from './types';
+import { checkQueryWithRelations } from './utils/check-query-with-relations';
+
+let predicateId = 1_000_000;
+
+/** Creates a value-based query filter. Predicate dependencies must be data traits. */
+export function createPredicate<T extends Trait[]>(
+    dependencies: [...T],
+    predicate: (values: PredicateValues<T>) => boolean
+): Predicate<T> {
+    for (const dependency of dependencies) {
+        if (
+            isRelation(dependency) ||
+            isRelationPair(dependency) ||
+            dependency[$internal].type === 'tag'
+        ) {
+            throw new Error('Koota: Predicate dependencies must be non-tag traits, not relations.');
+        }
+    }
+
+    return Object.assign(createModifier('predicate', predicateId++, dependencies), { predicate }) as Predicate<T>;
+}
+
+export function matchesPredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const values: unknown[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        values.push(trait[$internal].get(getEntityId(entity), getStore(world, trait)));
+    }
+    return predicate.predicate(values as never);
+}
+
+export function checkPredicateFilters(world: World, query: QueryInstance, entity: Entity): boolean {
+    for (const predicate of query.predicates) if (!matchesPredicate(world, entity, predicate)) return false;
+    for (const predicate of query.notPredicates) if (matchesPredicate(world, entity, predicate)) return false;
+    return true;
+}
+
+export function checkPredicateTracking(query: QueryInstance, entity: Entity): boolean {
+    const eid = getEntityId(entity);
+    for (const tracking of query.predicateTracking) if (!tracking.events[eid]) return false;
+    return true;
+}
+
+export function resetPredicateTracking(query: QueryInstance, eid: number) {
+    for (const tracking of query.predicateTracking) tracking.events[eid] = 0;
+}
+
+export function initializePredicateTracking(world: World, query: QueryInstance) {
+    for (const tracking of query.predicateTracking) {
+        for (const entity of world[$internal].entityIndex.dense) {
+            tracking.previous[getEntityId(entity)] = matchesPredicate(world, entity, tracking.predicate) ? 1 : 0;
+        }
+    }
+}
+
+export function notifyPredicateDependencyChanged(world: World, entity: Entity, trait: Trait) {
+    const instance = world[$internal].traitInstances[trait.id];
+    if (!instance) return;
+
+    for (const query of instance.predicateQueries) {
+        const eid = getEntityId(entity);
+        for (const tracking of query.predicateTracking) {
+            if (!tracking.predicate.traits.includes(trait)) continue;
+            const previous = tracking.previous[eid] === 1;
+            const current = matchesPredicate(world, entity, tracking.predicate);
+            tracking.previous[eid] = current ? 1 : 0;
+            if (
+                (tracking.type === 'add' && current && !previous) ||
+                (tracking.type === 'remove' && !current && previous) ||
+                (tracking.type === 'change' && current !== previous)
+            ) tracking.events[eid] = 1;
+        }
+
+        const match =
+            checkPredicateTracking(query, entity) &&
+            (query.relationFilters?.length
+                ? checkQueryWithRelations(world, query, entity)
+                : query.check(world, entity));
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
