    function relationFn(
        target: RelationTarget,
        params?: Record<string, unknown>
    ): RelationPair<Trait<S>> {
        if (target === undefined) throw Error('Relation target is undefined');

        return {
            [$relationPair]: true,
            [$internal]: {
                relation: relationFn as Relation<Trait<S>>,
                target,
                params,
            },
        } as RelationPair<Trait<S>>;
    }

